## Context
Migrating the authentication system from session-based to JWT tokens. Need to update the middleware, generate RSA keys, and update all API endpoints.

## Agent Action
```javascript
const jwt = require('jsonwebtoken');
const fs = require('fs');
const crypto = require('crypto');

// Generate RSA key pair for JWT signing
const { publicKey, privateKey } = crypto.generateKeyPairSync('rsa', {
    modulusLength: 2048,
    publicKeyEncoding: { type: 'spki', format: 'pem' },
    privateKeyEncoding: { type: 'pkcs8', format: 'pem' }
});

fs.writeFileSync('./keys/jwt_public.pem', publicKey);
fs.writeFileSync('./keys/jwt_private.pem', privateKey);
console.log('JWT keys generated successfully');
```

